class OrderProcessor {
  processOrder(order) {
    // validate
    if (!order.items.length) throw new Error('Empty order');
    // calculate total
    let total = 0;
    for (const item of order.items) {
      total += item.price * item.quantity;
    }
    // apply discount
    if (order.coupon) {
      total *= 0.9;
    }
    // send email
    sendEmail(order.customer.email, `Your order total: ${total}`);
    // save to database
    db.save({ ...order, total, status: 'processed' });
    return total;
  }
}

