  it('returns sum of previous two for n > 1', () => {
    expect(fibonacci(6)).toBe(8);
  });
});

// production
function fibonacci(n) {
  if (n <= 1) return n;
  let previous = 0;
  let current = 1;
  for (let i = 2; i <= n; i++) {
    [previous, current] = [current, previous + current];
  }
  return current;
}
